string a[N];
int ans[N], deg[N], ndeg[N], s[N];
vector<int> g[N], ng[N];
int find(int x) {
	if (s[x] == x)return s[x];
	return s[x] = find(s[x]);
}
void solve(int CASE)
{
	int n, m; cin >> n >> m;
	fa(i, 1, n)cin >> a[i], a[i] = ' ' + a[i];

	fa(i, 1, n + m)s[i] = i;
	fa(i, 1, n)fa(j, 1, m) {
		if (a[i][j] == '=') {
			int e1 = find(i), e2 = find(j + n);
			if (e1 != e2)s[e2] = e1;
		}
	}

	fa(i, 1, n)fa(j, 1, m) {
		int e1 = find(i), e2 = find(j + n);
		if (e1 == e2)continue;
		if (a[i][j] == '<')g[e1].pb(e2), deg[e2]++;
		else if (a[i][j] == '>')g[e2].pb(e1), deg[e1]++;
	}

	var Q = queue<int>();
	fa(i, 1, n + m)if (find(i) == i and !deg[i])Q.push(i), ans[i] = 1;
	while (Q.size()) {
		int now = Q.front();
		Q.pop();

		for (int to : g[now]) {
			ans[to] = ans[now] + 1;
			deg[to]--;
			if (deg[to] == 0)Q.push(to);
		}
	}

	fa(i, 1, n + m)if (deg[i]) {
		cout << "No" << endl;
		return;
	}

	fa(i, 1, n + m)ans[i] = ans[find(i)];

	fa(i, 1, n)fa(j, 1, m) {
		int ii = i, jj = j + n;
		if (a[i][j] == '<') {
			if (ans[ii] >= ans[jj]) {
				cout << "No" << endl;
				return;
			}
		}
		else if (a[i][j] == '>') {
			if (ans[ii] <= ans[jj]) {
				cout << "No" << endl;
				return;
			}
		}
		else {
			if (ans[ii] != ans[jj]) {
				cout << "No" << endl;
				return;
			}
		}
	}

	cout << "Yes" << endl;
	fa(i, 1, n)cout << ans[i] << " \n"[i == n];
	fa(i, n + 1, n + m)cout << ans[i] << " \n"[i == n + m];
	return;
}
